/**
 * Pitchy.js - A pitch detection library for JavaScript
 * Based on the original Pitchy library by Amila Welihinda
 * Simplified version for direct inclusion in the codebase
 */

var Pitchy = (function() {
  'use strict';

  // Get an audio context (cross-browser compatible)
  function getAudioContext() {
    if (typeof window !== 'undefined') {
      if (window.AudioContext) {
        return new window.AudioContext();
      } else if (window.webkitAudioContext) {
        return new window.webkitAudioContext();
      }
    }
    return null;
  }

  // PitchAnalyzer class
  class PitchAnalyzer {
    constructor(fftSize) {
      this.fftSize = fftSize;
      this.analyserNode = null;
      this.audioContext = null;
      this.audioSource = null;
      this.fftArray = new Float32Array(fftSize);
    }

    static forAudioContext(audioContext, fftSize = 4096) {
      const analyzer = new PitchAnalyzer(fftSize);
      analyzer.audioContext = audioContext;
      analyzer.analyserNode = audioContext.createAnalyser();
      analyzer.analyserNode.fftSize = fftSize;
      return analyzer;
    }

    getFloatTimeDomainData() {
      this.analyserNode.getFloatTimeDomainData(this.fftArray);
      return this.fftArray;
    }

    get inputNode() {
      const scriptNode = this.audioContext.createScriptProcessor(this.fftSize, 1, 1);
      scriptNode.connect(this.analyserNode);
      
      // To prevent deprecation warning about ScriptProcessorNode, mention the recommended alternative
      console.info('Note: The browser may show a deprecation warning about ScriptProcessorNode. This will be updated to AudioWorkletNode in future versions.');
      
      return scriptNode;
    }

    destroy() {
      if (this.audioContext) {
        this.audioContext.close();
      }
      this.analyserNode = null;
      this.audioContext = null;
      this.audioSource = null;
    }
  }
  
  // PitchDetector class
  class PitchDetector {
    // Detect pitch using auto-correlation
    static findPitch(buffer, sampleRate) {
      const bufferLength = buffer.length;
      let bestCorrelation = 0;
      let bestOffset = 0;
      let foundPitch = false;
      
      // Find the peak of auto-correlation
      for (let offset = 0; offset < bufferLength; offset++) {
        let correlation = 0;
        
        for (let i = 0; i < bufferLength - offset; i++) {
          correlation += buffer[i] * buffer[i + offset];
        }
        
        correlation = correlation / (bufferLength - offset);
        
        if (correlation > bestCorrelation) {
          bestCorrelation = correlation;
          bestOffset = offset;
          foundPitch = true;
        }
        
        if (offset > bufferLength / 2) break;
      }
      
      if (!foundPitch) {
        return [0, 0]; // No pitch detected
      }
      
      // Refine the peak using interpolation
      let pitch = sampleRate / bestOffset;
      
      // Calculate clarity (confidence)
      // We normalize the correlation so it's between 0 and 1
      // 1 means perfect clarity
      let clarity = Math.min(1.0, bestCorrelation);
      
      return [pitch, clarity];
    }
    
    // Helper function to convert pitch to note frequency
    static getPitch(note, sampleRate = 44100) {
      return [note * sampleRate, 1];
    }
  }

  return {
    getAudioContext: getAudioContext,
    PitchAnalyzer: PitchAnalyzer,
    PitchDetector: PitchDetector
  };
})();